import { ChatFlow } from 'flowise/dist';

const detectTokenSpike = (chatflow: ChatFlow, executionData: any) => {
  const llmNodes = chatflow.nodes.filter((node: any) => node.type.includes('LLM'));
  const totalTokens = executionData.metrics?.reduce((sum: number, metric: any) => {
    return sum + (metric.input_tokens || 0) + (metric.output_tokens || 0);
  }, 0) || 0;

  return {
    issue: 'HIGH_TOKEN_USAGE',
    severity: totalTokens > 8000 ? 'HIGH' : 'MEDIUM',
    metrics: { totalTokens, llmNodes: llmNodes.length }
  };
};

const detectSequentialLatency = (chatflow: ChatFlow) => {
  const llmNodes = chatflow.nodes.filter((node: any) => 
    node.type.includes('LLM') || node.type.includes('Agent')
  );

  const sequentialChains = llmNodes.filter((node: any, index: number) => {
    if (index === 0) return false;
    const prevNode = llmNodes[index - 1];
    return node.data.edges?.some((edge: any) => edge.source === prevNode.id);
  });

  return {
    issue: 'SEQUENTIAL_LLM_CHAIN',
    severity: sequentialChains.length > 2 ? 'HIGH' : 'MEDIUM',
    count: sequentialChains.length
  };
};

const detectPoorRetrieval = (toolNodeData: any) => {
  const docs = toolNodeData.documents || [];
  const scores = docs.map((doc: any) => doc.metadata?.score || 0);
  const avgScore = scores.reduce((a: number, b: number) => a + b, 0) / scores.length;
  const maxScore = Math.max(...scores);

  return {
    issue: 'LOW_RETRIEVAL_RELEVANCE',
    severity: avgScore < 0.7 || maxScore < 0.5 ? 'HIGH' : 'LOW',
    metrics: { avgScore: avgScore.toFixed(3), maxScore: maxScore.toFixed(3) }
  };
};

