import { Vex } from '@vex_dev/sdk';
import { ChatFlow } from 'flowise/dist';

// Initialize Vex in Flowise config
const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY!,
  monitor: {
    latency: { threshold: '2s' },
    tokens: { threshold: 4000 },
    retrieval: { relevance: 0.75 }
  }
});

// Add Vex as callback handler
const chatflow = new ChatFlow();
chatflow.callbacks.push({
  onChainStart: vex.onChainStart.bind(vex),
  onChainEnd: async (outputs) => {
    const result = await vex.onChainEnd(outputs);
    if (result.issues.length > 0) {
      console.log('Vex detected:', result.issues);
      // Auto-apply fixes
      await vex.applyFixes(chatflow, result.recommendations);
    }
  },
  onToolStart: vex.onToolStart.bind(vex),
  onToolEnd: vex.onToolEnd.bind(vex)
});

// Export optimized flow
chatflow.setVexOptimization('llm-latency');
